        category: transaction.category,
        transactions: [transaction],
        total: transaction.amount,
      });
    }
  }

  return Array.from(map.values());
}
```

### Step 2: `findDuplicates` (lines 49–93)

**Current bottleneck:** O(n^2) — pairwise comparison of every transaction, plus linear scans for group lookup and membership checks.

**Optimization:** Single pass: build a `Map<string, Transaction[]>` keyed by `${userId}|${amount}|${date}`. Then filter to only groups with 2+ transactions and map to `DuplicateGroup` objects.

**New complexity:** O(n)

```typescript
export function findDuplicates(transactions: Transaction[]): DuplicateGroup[] {
  const map = new Map<string, Transaction[]>();

  for (const t of transactions) {
    const key = `${t.userId}|${t.amount}|${t.date}`;
    const group = map.get(key);
    if (group) {
      group.push(t);
    } else {
      map.set(key, [t]);
    }
  }

  const result: DuplicateGroup[] = [];
  for (const [key, transactions] of map) {
    if (transactions.length > 1) {
      result.push({ key, transactions });
    }
  }
  return result;
}
```

### Step 3: `calculateRunningBalance` (lines 102–146)

**Current bottleneck:** O(n * m^2) — for each position in the user's transaction list, rescans ALL transactions to re-filter, re-sort, and recalculate balance from scratch.

**Optimization:** Filter user's transactions in one pass (O(n)), sort once (O(m log m)), compute running balance in a single pass (O(m)). Preserve `Math.round(balance * 100) / 100` rounding.

**New complexity:** O(n + m log m)

```typescript
export function calculateRunningBalance(
  transactions: Transaction[],
  userId: string
): RunningBalanceEntry[] {
  const userTransactions: Transaction[] = [];
  for (const t of transactions) {
    if (t.userId === userId) {
      userTransactions.push(t);
    }
  }

  userTransactions.sort((a, b) => a.date.localeCompare(b.date));

  const entries: RunningBalanceEntry[] = [];
  let balance = 0;
  for (const t of userTransactions) {
    balance += t.amount;
    entries.push({
      transactionId: t.id,
      amount: t.amount,
      balance: Math.round(balance * 100) / 100,
      date: t.date,
    });
  }

  return entries;
}
```

### Step 4: `topSpenders` (lines 154–196)

**Current bottleneck:** O(n * u + u^2) — `userIds.includes()` for dedup (O(n*u)), rescans all transactions per user (O(n*u)), bubble sort (O(u^2)).

**Optimization:** Single pass with `Map<string, { total: number; count: number }>` to accumulate per-user totals. Use native `.sort()` (O(u log u)) instead of bubble sort. Preserve `Math.round(total * 100) / 100`.

**New complexity:** O(n + u log u)

```typescript
export function topSpenders(
  transactions: Transaction[],
  n: number
): SpenderSummary[] {
  const map = new Map<string, { total: number; count: number }>();

  for (const t of transactions) {
    const entry = map.get(t.userId);
    if (entry) {
      entry.total += t.amount;
      entry.count++;
    } else {
      map.set(t.userId, { total: t.amount, count: 1 });
    }
  }

  const summaries: SpenderSummary[] = [];
  for (const [userId, { total, count }] of map) {
    summaries.push({
      userId,
      totalSpent: Math.round(total * 100) / 100,
      transactionCount: count,
    });
  }

  summaries.sort((a, b) => b.totalSpent - a.totalSpent);
  return summaries.slice(0, n);
}
```

### Step 5: `searchTransactions` (lines 204–232)

**Current bottleneck:** Creates a new `RegExp` for every transaction (regex compilation is expensive at 100k scale) + linear dedup scan on results.

**Optimization:** Compile the RegExp once before the loop. Use a `Set<string>` for O(1) dedup by transaction ID.

**New complexity:** O(n)

```typescript
export function searchTransactions(
  transactions: Transaction[],
  query: string
): Transaction[] {
  const pattern = new RegExp(query.replace(/[.*+?^${}()|[\]\\]/g, "\\$&"), "i");
  const results: Transaction[] = [];
  const seen = new Set<string>();

  for (const transaction of transactions) {
    if (pattern.test(transaction.description) && !seen.has(transaction.id)) {
      seen.add(transaction.id);
      results.push(transaction);
    }
  }

  return results;
}
```

### Step 6: `processAll` (lines 237–250)

**No changes needed.** Once the component functions are optimized, the combined pipeline will easily meet the 200ms threshold for 20k transactions.

---

## Verification

Run the full test suite to confirm both correctness and performance:

```bash
npm test
```

This executes both `tests/pipeline.test.ts` (26 correctness tests) and `tests/performance.test.ts` (6 performance benchmarks). All 32 tests must pass.

